/**
 * MedX container layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Max-width containers for detail pages.
 */
const CONTAINER_TOKENS = Object.freeze({
  primary: { value: "layout-container-primary", scope: "layout" },
  secondary: { value: "layout-container-secondary", scope: "layout" },
  muted: { value: "layout-container-muted", scope: "layout" },
  accent: { value: "layout-container-accent", scope: "layout" },
  surface: { value: "layout-container-surface", scope: "layout" },
});

const CONTAINER_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const CONTAINER_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const containerRegistry = new Map();
const CONTAINER_listeners = new Set();
let CONTAINER_seq = 0;

function createContainerId(prefix = "medx-layout-container") {
  CONTAINER_seq += 1;
  return `${prefix}-${CONTAINER_seq}`;
}

function registerContainer(config = {}) {
  const entryId = config.id ?? createContainerId();
  const preset = CONTAINER_PRESETS[config.preset ?? "default"] ?? CONTAINER_PRESETS.default;
  const token = CONTAINER_TOKENS[config.token ?? preset.token] ?? CONTAINER_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: CONTAINER_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  containerRegistry.set(entryId, entry);
  notifyContainerListeners("register", entry);
  return entry;
}

function updateContainer(id, patch = {}) {
  const entry = containerRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyContainerListeners("update", entry);
  return entry;
}

function resolveContainer(id) {
  const entry = containerRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listContainerEntries(filter = {}) {
  let items = Array.from(containerRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onContainerEvent(listener) {
  CONTAINER_listeners.add(listener);
  return () => CONTAINER_listeners.delete(listener);
}

function notifyContainerListeners(type, entry) {
  for (const listener of CONTAINER_listeners) {
    try {
      listener({ type, entry, registrySize: containerRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:container] listener error", err.message);
    }
  }
}

function getContainerMetrics() {
  const items = listContainerEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(CONTAINER_TOKENS).length,
    presets: Object.keys(CONTAINER_PRESETS).length,
  };
}

async function runMedxContainer() {
  console.log("[medx:ui:layout:container] runtime initialized");
  console.log(`[medx:ui:layout:container] tokens=${Object.keys(CONTAINER_TOKENS).length} presets=${Object.keys(CONTAINER_PRESETS).length}`);

  const events = [];
  onContainerEvent((e) => events.push(e.type));

  const domains = Object.keys(CONTAINER_SUPPLY_CHAIN);
  const presets = Object.keys(CONTAINER_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerContainer({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/container" },
    });
  }

  const first = listContainerEntries()[0];
  if (first) updateContainer(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getContainerMetrics();
  const resolved = first ? resolveContainer(first.id) : null;

  console.log(`[medx:ui:layout:container] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:container] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:container] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:container] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:container] bootstrap complete");
}

module.exports = runMedxContainer;
